from typing import List

class Solution:
    def solve(self, s1: str, s2: str) -> int:
        n = len(s1)
        res = 0
        for i in range(n // 2):
            if s1[i] == s2[n - i - 1]:
                continue
            else:
                res += 1
        return res

if __name__ == '__main__':
    s1 = input()
    s2 = input()
    solution = Solution()
    print(solution.solve(s1, s2))

