#include <bits/stdc++.h>

class Solution {
public:
    int minSwaps(std::string s1, std::string s2) {
        int n = s1.length();
        int res = 0;
        for (int i = 0; i < n / 2; i++) {
            if (s1[i] == s2[n - i - 1]) {
                continue;
            } else {
                res++; // BUG: increment the counter for every different pair of characters
            }
        }
        return res;
    }
};

int main() {
    std::ios_base::sync_with_stdio(false);
